const tickers = [
  'AAPL', 'MSFT', 'NVDA', 'GOOGL', 'META',
  'AMZN', 'TSLA', 'JPM',  'V',     'MA',
  'UNH',  'LLY',  'XOM',  'CVX',   'HD',
  'COST', 'AVGO', 'ASML', 'AMD',   'NFLX',
];
return tickers.map(ticker => ({ json: { ticker } }));

const item = $input.first().json;
const ticker = item.meta?.symbol ?? 'UNKNOWN';
const closes = item.indicators?.quote?.[0]?.close ?? [];
const volumes = item.indicators?.quote?.[0]?.volume ?? [];
if (closes.length < 50) return [{ json: { ticker, skip: true } }];
function calcRSI(prices, period = 14) {
  let gains = 0, losses = 0;
  for (let i = 1; i <= period; i++) { const d = prices[i]-prices[i-1]; if(d>0) gains+=d; else losses-=d; }
  let avgGain = gains/period, avgLoss = losses/period;
  for (let i = period+1; i < prices.length; i++) { const d=prices[i]-prices[i-1]; avgGain=(avgGain*(period-1)+Math.max(d,0))/period; avgLoss=(avgLoss*(period-1)+Math.max(-d,0))/period; }
  return avgLoss===0 ? 100 : 100-100/(1+avgGain/avgLoss);
}
function calcEMA(prices, period) { const k=2/(period+1); let ema=prices.slice(0,period).reduce((a,b)=>a+b,0)/period; for(let i=period;i<prices.length;i++) ema=prices[i]*k+ema*(1-k); return ema; }
const ema12=calcEMA(closes,12), ema26=calcEMA(closes,26), macdLine=ema12-ema26;
const macdSeries=closes.slice(-35).map((_,i,arr)=>{ const s=closes.slice(0,closes.length-arr.length+i+1); return calcEMA(s,12)-calcEMA(s,26); });
const signalLine=calcEMA(macdSeries,9);
const sma50=closes.slice(-50).reduce((a,b)=>a+b,0)/50;
const recentVol=volumes.slice(-5).reduce((a,b)=>a+(b??0),0)/5;
const avgVol20=volumes.slice(-20).reduce((a,b)=>a+(b??0),0)/20;
const volumeRatio=avgVol20>0?recentVol/avgVol20:1;
const price30dAgo=closes[closes.length-31]??closes[0];
const currentPrice=closes[closes.length-1];
const priceChange30d=((currentPrice-price30dAgo)/price30dAgo)*100;
return [{ json: { ticker, currentPrice: Math.round(currentPrice*100)/100, rsi: Math.round(calcRSI(closes)*10)/10, macdLine: Math.round(macdLine*100)/100, macdCrossingUp: macdLine>signalLine&&macdLine>0, aboveSMA50: currentPrice>sma50, volumeRatio: Math.round(volumeRatio*100)/100, priceChange30d: Math.round(priceChange30d*10)/10 } }];

const stocks = $input.all().map(i => i.json).filter(s => !s.skip);
if (stocks.length === 0) return [{ json: { prompt: null, error: 'No stocks passed the filter.' } }];
const today = new Date().toISOString().split('T')[0];
const stockTable = stocks.map(s => `${s.ticker}: price=$${s.currentPrice} RSI=${s.rsi} MACD=${s.macdLine}(${s.macdCrossingUp?'crossing up':'flat'}) vs50SMA=${s.aboveSMA50?'above':'below'} volRatio=${s.volumeRatio}x 30d%=${s.priceChange30d}%`).join('
');
const prompt = `You are a swing trading analyst. The investor's strategy is to hold positions for 1–2 months, targeting 10–25% gains.

Today: ${today}
Screening data for ${stocks.length} stocks:
${stockTable}

Scoring criteria:
- RSI between 40–65
- MACD crossing up
- Price above 50-day SMA
- Volume ratio > 1.2
- Not already up 20%+ in 30 days

Task: Score each stock (0–5), select TOP 3.

Respond ONLY in this exact JSON (no markdown):
{"date":"${today}","picks":[{"ticker":"AAPL","score":4,"reason":"...","risk":"..."}],"summary":"..."}`;
return [{ json: { prompt, stockCount: stocks.length } }];

const raw = $input.first().json.content?.[0]?.text ?? '';
let data;
try { const cleaned = raw.replace(/^```json\s*/i,'').replace(/\s*```$/,'').trim(); data = JSON.parse(cleaned); } catch(e) { return [{ json: { parseError: true, message: '❌ Could not parse Claude response. Check Executions.' } }]; }
if (!data.picks || !Array.isArray(data.picks)) return [{ json: { parseError: true, message: '❌ Unexpected JSON shape.' } }];
return [{ json: data }];

const data = $input.first().json;
if (data.parseError) return [{ json: { message: data.message } }];
const medals = ['🥇','🥈','🥉'];
const lines = [`📈 <b>Swing Trade Picks — ${data.date}</b>\n`,`<i>${data.summary}</i>\n`];
data.picks.forEach((p,i) => { lines.push(`${medals[i]??'#'+(i+1)} <b>${p.ticker}</b> (score: ${p.score}/5)`,`💡 ${p.reason}`,`⚠️ Risk: ${p.risk}\n`); });
lines.push('<i>Not financial advice. Do your own research.</i>');
return [{ json: { message: lines.join('\n') } }];

const errData = $input.first().json;
const errMsg = errData.error?.message ?? errData.message ?? JSON.stringify(errData).slice(0,200);
return [{ json: { message: `❌ <b>Stock Bot Error</b>

The picks run failed at the Claude API step.

<code>${errMsg}</code>

Check <b>n8n → Executions</b> for the full trace.` } }];
